INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (289109, 46169, 9, 'erangolani27', 'Both are visceral, large-scale war epics that place you inside the chaos of battle; if the Omaha Beach landing left you shaken, the Scottish highlands siege will do the same.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (289109, 39551, 10, 'erangolani27', 'Back-to-back watches of modern combat cinema at its most unrelenting; both strip away heroics and replace them with exhausting, ground-level survival.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (289109, 121538, 9, 'erangolani27', 'Both dissect the machinery of war from the inside, one through the beaches of Normandy, the other through the jungles of Vietnam, each leaving you hollow in the best way.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (289109, 257459, 9, 'erangolani27', 'Two unflinching portraits of infantry combat that refuse to romanticise the experience; fans of one almost universally rate the other just as highly.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (289109, 18960, 9, 'erangolani27', 'Moving from Spielberg''s World War II realism to Coppola''s hallucinatory Vietnam is a natural double bill for anyone drawn to war cinema that goes beyond spectacle.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (289109, 330388, 8, 'erangolani27', 'Released the same year and covering the same war, Malick''s meditative counterpoint to Spielberg''s kinetic approach rewards anyone who wants both sides of the coin.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (18960, 121538, 9, 'erangolani27', 'Two Vietnam masterpieces that approach the same war from radically different angles; Kubrick''s detached irony and Coppola''s fever-dream immersion complement each other perfectly.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (18960, 326155, 9, 'erangolani27', 'Both feature isolated, psychologically fractured men driven to a violent endpoint; Scorsese''s Travis Bickle is Travis-as-urban-soldier, Willard is Bickle-sent-upriver.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (267038, 131780, 10, 'erangolani27', 'The two films that redefined crime cinema in the nineties; Tarantino''s fragmented cool and Scorsese''s propulsive rise-and-fall share DNA that makes each one richer after you have seen the other.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (267038, 164572, 9, 'erangolani27', 'Tarantino''s quieter follow-up rewards fans of Pulp Fiction who want the same sharp dialogue and moral ambiguity delivered at a more deliberate pace.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (267038, 176711, 9, 'erangolani27', 'Moving from Tarantino''s interlocking crime vignettes to his operatic revenge saga is a seamless journey through the same obsessive cinephile sensibility.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (267038, 306032, 9, 'erangolani27', 'Ritchie''s British crime comedy borrows Pulp Fiction''s overlapping-storylines structure and snappy ensemble energy; fans of one almost always embrace the other.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (267038, 276217, 10, 'erangolani27', 'Tarantino''s debut and his breakthrough are inseparable companion pieces that together define his entire aesthetic blueprint.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (131780, 56304, 10, 'erangolani27', 'Scorsese''s two definitive mob epics share a narrator-driven rise-and-fall arc, a period soundtrack, and the same commitment to showing the seductive rot of organised crime.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (131780, 130128, 10, 'erangolani27', 'The two pillars of American crime cinema; watching both back to back reveals how differently Coppola''s operatic formality and Scorsese''s street-level kinetics approach the same underworld.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (131780, 82967, 9, 'erangolani27', 'Scorsese revisiting crime from a new angle; fans of his classic mob work will find the Boston setting and duplicity-driven plot equally electrifying.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (291698, 247579, 9, 'erangolani27', 'Both are Fincher exercises in confined, escalating dread; Se7en uses a whole city as its trap, Panic Room shrinks the walls to a single house with equally suffocating effect.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (291698, 123435, 9, 'erangolani27', 'Three consecutive Fincher films that share a cold visual palette and a hero who is methodically stripped of control; the paranoid tension transfers perfectly from one to the next.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (291698, 348944, 9, 'erangolani27', 'Both were released the same year and both end with a revelation that reframes everything you just watched; a natural double feature for thriller fans.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (291698, 210511, 9, 'erangolani27', 'Se7en''s procedural darkness and Memento''s fractured chronology both weaponise narrative structure to maximise dread; fans of one consistently respond to the other.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (297838, 253010, 9, 'erangolani27', 'Both are slow-burn stories of confined or hunted men that use an unlikely relationship to carry enormous emotional weight; the redemptive pull is almost identical.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (297838, 313059, 9, 'erangolani27', 'Both are Stephen King adaptations built around male friendship, loyalty, and a defining journey; they share the same warm, melancholic register.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (62076, 70248, 9, 'erangolani27', 'Both were released the same year and are the finest expressions of Seventies paranoia cinema; one uses private investigation, the other surveillance, to reach equally bleak conclusions.', null);

