INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (82967, 56304, 9, 'erangolani27', 'Scorsese at his most operatic versus Scorsese at his most precise; the duplicity and violence of The Departed find their natural companion in Casino''s slow-burn corruption.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (82967, 209158, 8, 'erangolani27', 'Tracing Scorsese from his raw early street-level work to his polished late-career masterpiece shows how consistent his obsessions with loyalty and betrayal have always been.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (82967, 270971, 8, 'erangolani27', 'Both are unsparing portraits of self-destructive men who cannot separate identity from violence; De Niro''s LaMotta and DiCaprio''s Billy Costigan operate on the same wavelength.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (30959, 30955, 9, 'erangolani27', 'The two most creatively distinctive takes on the character; Burton''s gothic expressionism and Nolan''s grounded realism are poles apart yet equally committed to their own vision.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (30959, 207992, 8, 'erangolani27', 'Both represent a turning point in action cinema where philosophical weight and practical craft combined to make genuinely intelligent blockbusters.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (176711, 164572, 8, 'erangolani27', 'Jackie Brown''s slow-burn character study is the ideal companion to Kill Bill''s kinetic maximalism; both show Tarantino''s range and his deep love of genre cinema.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (176711, 176712, 10, 'erangolani27', 'The two halves of one film; Vol. 1 sets up the violence with style and Vol. 2 delivers the emotional and dramatic payoff that makes the journey worthwhile.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (194497, 194502, 10, 'erangolani27', 'The first two parts of one of cinema''s greatest continuous narratives; Fellowship establishes the world with breathtaking care, Two Towers expands it with the extraordinary Helm''s Deep sequence.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (194497, 194500, 10, 'erangolani27', 'Fellowship sets up a journey that Return of the King concludes with rare emotional satisfaction; the trilogy functions as a single extended film and should be experienced as such.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (194502, 194500, 10, 'erangolani27', 'The last two thirds of Jackson''s trilogy are inseparable; Two Towers raises the stakes and Return of the King delivers on every thread with a finale that earns its extended runtime.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (313478, 313459, 10, 'erangolani27', 'The original and its superior sequel form the core of the saga; Empire adds darkness, complexity, and the franchise''s most shocking revelation to the universe A New Hope created.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (313478, 313479, 9, 'erangolani27', 'Empire raises every dramatic stake and Return of the Jedi resolves them with genuine emotional weight; together they form the most satisfying consecutive films in the saga.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (120574, 130953, 9, 'erangolani27', 'The two films that defined the Bond formula at its most refined; back-to-back they show Connery at his absolute peak and the series at its most focused and intelligent.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (120574, 240521, 8, 'erangolani27', 'The two most dramatically grounded early Bond films; both take the threat seriously and pay an emotional price that most entries in the series avoid entirely.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (130945, 120574, 8, 'erangolani27', 'GoldenEye revitalised the franchise by returning to the Cold War tension and grounded espionage that made From Russia with Love so effective decades earlier.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (299073, 303564, 9, 'erangolani27', 'Both are psychological horror films that use dread rather than gore to unsettle; Kubrick''s slow architectural horror and Shyamalan''s ghost story share a commitment to atmosphere over shock.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (299073, 240327, 8, 'erangolani27', 'Two of the defining Seventies supernatural horror films; both use a domestic setting and a slow build to create a sense of inescapable doom rather than cheap scares.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (303564, 123435, 9, 'erangolani27', 'Both are built entirely around a structural revelation that forces you to re-evaluate every scene you just watched; the rewatch value is identical and equally rewarding.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (137655, 299073, 9, 'erangolani27', 'The two films that together defined atmospheric horror at the end of the Seventies; Carpenter''s minimalism and Kubrick''s maximalism both use silence and space to generate sustained dread.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (191246, 337166, 9, 'erangolani27', 'Released a year apart, these are the two films that defined what animation could achieve in the Nineties; both use their medium to deliver genuinely affecting emotional narratives.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (191246, 218219, 8, 'erangolani27', 'Lion King''s operatic scope and Mononoke''s ecological complexity are the Eastern and Western peaks of Nineties feature animation; together they show the full range of what the medium can carry.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (337166, 59578, 8, 'erangolani27', 'Both are fantasies built around the idea that imagination and friendship are more powerful than anything the adult world can offer; the emotional core is strikingly similar.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (174953, 218219, 10, 'erangolani27', 'Miyazaki''s two great ecological epics that bookend his mature period; both feature a young woman navigating a world on the brink of environmental collapse with grace and determination.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (270971, 326155, 9, 'erangolani27', 'De Niro''s two most devastating Scorsese collaborations; both study men destroyed by their own internal violence, and both remain the benchmark for actor-director partnerships in American cinema.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (270971, 280270, 8, 'erangolani27', 'The definitive boxing film and the ultimate anti-boxing film released within four years of each other; Rocky sells the dream and Raging Bull dismantles it with equal power.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (280270, 280281, 9, 'erangolani27', 'Rocky II is the rare sequel that earns its existence by deepening the original''s emotional stakes rather than simply repeating them; the two form a natural dramatic unit.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (56871, 123849, 8, 'erangolani27', 'Both 2002 films showcase DiCaprio operating at his most charismatic and confident; together they mark the moment he fully crossed from teen idol to serious leading man.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (185628, 46169, 8, 'erangolani27', 'Both are sweeping historical epics where an outsider finds honour and identity within a warrior culture facing extinction; the emotional arc and visual scale are very similar.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (200521, 267038, 8, 'erangolani27', 'Both use a mosaic of interlocking stories to find unexpected emotional connections between strangers; Magnolia takes Pulp Fiction''s structural ambition and turns it toward something rawer and more openly devastating.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (67395, 14477, 9, 'erangolani27', 'Two Spielberg films that confront American history''s most painful chapters with equal gravity; both rest on towering central performances and refuse to look away from suffering.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (30686, 276085, 9, 'erangolani27', 'The two most harrowing portraits of addiction in American cinema of that era; Basketball Diaries uses DiCaprio''s physical commitment, Requiem uses Aronofsky''s formal assault to achieve the same devastating effect.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (254986, 290070, 10, 'erangolani27', 'The two most essential Holocaust films in the canon; Spielberg''s sweep and Polanski''s intimacy are complementary perspectives on the same historical catastrophe.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (238072, 306032, 9, 'erangolani27', 'Both are slick, endlessly rewatchable heist ensemble films that prioritise wit and style over tension; the pleasure in each comes from watching smart people execute an elegant plan.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (238072, 208245, 8, 'erangolani27', 'Both are charming ensemble capers where the pleasure comes entirely from watching supremely confident characters outmanoeuvre everyone around them with a grin.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (256632, 271095, 9, 'erangolani27', 'Both are the definitive adventure films of their respective decades; Depp''s Sparrow and Ford''s Jones occupy the same space of roguish, instinctive heroism that audiences find irresistible.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (256632, 340652, 8, 'erangolani27', 'Both are big-budget historical adventure epics anchored by charismatic leads; fans of Pirates'' swashbuckling scale will find Troy''s epic ambition equally satisfying.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (141544, 131780, 9, 'erangolani27', 'Both are meticulous, long-form crime epics that treat their world with the seriousness of a documentary; the diner scene in Heat and the Copacabana tracking shot in Goodfellas are two of cinema''s great single moments.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (141544, 56304, 9, 'erangolani27', 'Both were released the same year and together represent the peak of Nineties crime cinema; Heat''s procedural precision and Casino''s operatic excess are complementary approaches to the same world.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (141544, 291698, 8, 'erangolani27', '1995 was the finest year for serious crime cinema in decades; Heat and Se7en represent its two poles, one a classical procedural and the other a psychological assault.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (130128, 56304, 9, 'erangolani27', 'The founding text and one of the finest extensions of American crime cinema; Coppola''s operatic family tragedy and Scorsese''s Vegas deconstruction speak the same language across twenty years.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (49696, 62076, 8, 'erangolani27', 'Both are genre films that use the conventions of their form to deliver something far darker and more morally complex than their surfaces suggest; the endings of each are among cinema''s most memorable.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (348944, 123435, 9, 'erangolani27', 'Two of the finest twist thrillers ever made; The Usual Suspects inverts your understanding of what you saw and The Game does the same to your understanding of what is real.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (26844, 131885, 9, 'erangolani27', 'Two 1985 adventure films that defined what it meant to be a child who loved movies in the Eighties; the sense of invention, stakes, and pure cinematic joy is identical in both.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (186439, 130128, 9, 'erangolani27', 'The two films most often cited as the pinnacle of classical Hollywood storytelling; both use vast canvases to tell intimate stories about men consumed by the roles history forces on them.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (233058, 299073, 8, 'erangolani27', 'Both are slow-burn supernatural thrillers built around a solitary protagonist drawn deeper into an occult mystery; the unsettling atmosphere in each rewards patient viewers.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (106790, 62076, 8, 'erangolani27', 'Both use genre conventions to excavate longing, loss, and moral failure; Wong Kar-wai''s lush restraint and Polanski''s cynical noir are stylistically opposite but thematically inseparable.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (313059, 26844, 8, 'erangolani27', 'Both are deeply Eighties films built on nostalgia and the specific texture of American boyhood; Stand by Me is the elegiac version of the same emotional territory Back to the Future celebrates.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (280270, 280282, 7, 'erangolani27', 'Rocky III trades the original''s gritty realism for a more commercial formula but retains enough of Stallone''s commitment and the underdog spirit to make it a satisfying if lighter companion.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (130953, 240521, 8, 'erangolani27', 'Two of the most dramatically ambitious early Bond films; Goldfinger perfects the formula and OHMSS is the one entry that dares to break it with genuine emotional consequence.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (254986, 67395, 9, 'erangolani27', 'Both are slow, devastating portraits of survival under oppression anchored by extraordinary central performances; the emotional weight is equally distributed across every scene.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (276085, 326155, 8, 'erangolani27', 'Both are exercises in slow psychological disintegration; Aronofsky''s formal assault and Scorsese''s street-level realism channel the same fascination with minds that cannot be saved from themselves.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (276085, 299073, 8, 'erangolani27', 'Both use filmmaking technique itself as a tool of psychological horror; Aronofsky''s rapid editing and Kubrick''s static geometry are different methods of placing you inside a deteriorating mind.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (210511, 116556, 9, 'erangolani27', 'Nolan''s two early films that established his signature interest in fractured chronology and unreliable identity; Following is the rough blueprint for everything Memento perfected.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (210511, 123435, 9, 'erangolani27', 'Both are paranoid thrillers where the protagonist cannot trust their own perception of events; the structural disorientation in each is used to maximise genuine suspense rather than mere confusion.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (94741, 96593, 8, 'erangolani27', 'Both demonstrate Spielberg''s mastery of building enormous tension and wonder from minimal ingredients; Duel uses a truck and an empty road, E.T. uses a boy and a bicycle.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (238073, 238072, 7, 'erangolani27', 'Ocean''s Twelve is a looser and more self-indulgent film than its predecessor but shares enough of the ensemble''s chemistry and playful energy to reward fans who want another round with the same crew.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (164572, 276217, 8, 'erangolani27', 'The quietest and the most explosive entries in Tarantino''s catalogue; both show his command of dialogue, character, and tension even when the approach is completely different.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (159665, 267038, 9, 'erangolani27', 'Both showcase Tarantino''s signature ability to make extended dialogue scenes feel more dangerous and exciting than most directors'' action sequences; Waltz''s Hans Landa belongs in the same conversation as Jules Winnfield.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (159665, 164572, 8, 'erangolani27', 'Both demonstrate Tarantino''s skill at building tension through conversation; the basement bar scene in Inglourious Basterds and the mall finale in Jackie Brown show the same craftsman at work.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (160524, 291698, 8, 'erangolani27', 'Both are crime procedurals where the detective''s internal moral collapse runs parallel to the external investigation; the Alaskan daylight in Insomnia and Se7en''s perpetual rain are equally oppressive environments.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (160524, 210511, 8, 'erangolani27', 'Two thriller films built around compromised protagonists whose relationship with truth and memory defines the entire narrative; Nolan''s interest in unreliable minds is consistent across both.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (267038, 118367, 2, 'erangolani27', 'Four Rooms shares Tarantino''s anthology structure and one of his segments, but the wildly uneven quality and self-indulgent direction from three of the four directors make it a frustrating experience after Pulp Fiction''s perfection.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (131780, 1390, 1, 'erangolani27', 'Both are crime-and-chaos films but 1941''s slapstick excess and narrative incoherence are everything Goodfellas'' precision is not; the contrast is almost educational.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (289109, 359297, 2, 'erangolani27', 'Both are Spielberg directing Tom Hanks or Cruise through extraordinary stakes, but War of the Worlds sacrifices the human specificity that made Saving Private Ryan essential for hollow spectacle.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (271095, 159167, 2, 'erangolani27', 'The original is a model of practical adventure filmmaking; the fourth entry drowns its hero in CGI and a plot that never generates the same breathless invention.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (194497, 313474, 2, 'erangolani27', 'Both launched major fantasy trilogies in roughly the same era, but Phantom Menace''s dramatic flatness and over-reliance on digital world-building make it a sobering contrast to Fellowship''s rich, tactile craft.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (313478, 313476, 2, 'erangolani27', 'Empire is the franchise at its most emotionally and dramatically complex; Attack of the Clones is the prequel trilogy at its most stilted, with a romance subplot that undermines everything Empire did so well.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (313459, 313474, 2, 'erangolani27', 'Watching the original and the first prequel back to back is a study in how franchise filmmaking can lose its soul; one is lean and mythic, the other bloated and dramatically inert.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (30959, 30952, 1, 'erangolani27', 'Batman Begins represents the character treated with total seriousness; Batman and Robin represents his nadir, a film so misguided it nearly ended the franchise entirely.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (30955, 30952, 1, 'erangolani27', 'Burton''s gothic original has real personality and craft; Batman and Robin has neither, and the contrast between them is one of the steepest quality drops in franchise history.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (280270, 280305, 2, 'erangolani27', 'Rocky is a model of stripped-back underdog storytelling; Rocky V strips away everything that made the original resonate without replacing it with anything of comparable value.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (256632, 256631, 3, 'erangolani27', 'The original is a tightly constructed adventure with a fresh central performance; the sequel piles on subplots and set-pieces until the whole thing loses the focused charm that made the first work.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (300229, 300230, 5, 'erangolani27', 'Shrek''s subversive wit is genuinely surprising the first time; Shrek 2 is a competent and entertaining sequel but the surprise is gone and the jokes rely more heavily on pop-culture references that have aged less gracefully.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (188507, 188511, 2, 'erangolani27', 'The original Lethal Weapon works because the central relationship feels dangerous and real; by the fourth film the formula is running entirely on fumes and goodwill.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (176711, 118367, 2, 'erangolani27', 'Kill Bill demonstrates Tarantino''s complete command of genre and tone; Four Rooms, which includes one of his segments, shows what happens when that vision is diluted by inconsistent collaborators.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (120574, 85871, 2, 'erangolani27', 'From Russia with Love is the Bond series at its most grounded and intelligent; Diamonds Are Forever is a campy regression that squanders Connery''s return with a plot that never takes itself seriously.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (120574, 218808, 1, 'erangolani27', 'The franchise''s most disciplined entry paired with its most absurd; Moonraker abandons all pretence of espionage realism in favour of a space-opera parody that betrays everything From Russia with Love established.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (120574, 86263, 1, 'erangolani27', 'The finest Cold War Bond thriller and the worst modern Bond entry represent the outer limits of what the franchise is capable of; the CGI and self-parody of Die Another Day are everything From Russia with Love is not.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (130953, 354178, 2, 'erangolani27', 'Goldfinger gave the franchise its template; A View to a Kill demonstrates how tired that template had become twenty years later, with an aging Moore going through motions the series had long since exhausted.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (130945, 335336, 2, 'erangolani27', 'GoldenEye revitalised the Bond franchise with genuine tension and a strong villain; Tomorrow Never Dies, released just two years later, reverts to a generic media-mogul plot that wastes its premise.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (130945, 86263, 1, 'erangolani27', 'GoldenEye showed what a modern Bond film could achieve with craft and restraint; Die Another Day is the embarrassing end-point of the same era, undoing all that goodwill with excess and poor CGI.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (240521, 218808, 1, 'erangolani27', 'OHMSS is the one Bond film brave enough to let its hero suffer genuine loss; Moonraker''s campy space adventure represents the complete abandonment of that emotional ambition a decade later.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (299073, 44238, 1, 'erangolani27', 'The Shining is a masterclass in sustained psychological horror; Bordello of Blood is a cheap horror-comedy that mistakes gross-out gags for genuine unease.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (137655, 44238, 1, 'erangolani27', 'Halloween invented many of the tropes that Bordello of Blood later drains of all menace; watching both in sequence is a lesson in the difference between craft and exploitation.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (207992, 350424, 3, 'erangolani27', 'The Matrix uses its reality-questioning premise with visual and philosophical conviction; Vanilla Sky covers similar philosophical ground but buries it under a self-indulgent romantic mystery that never earns its ambition.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (40199, 218808, 1, 'erangolani27', 'Both are late-Seventies to early-Eighties science fiction, but Blade Runner uses its future setting for genuine philosophical inquiry while Moonraker reduces the genre to campy spectacle.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (297838, 200864, 1, 'erangolani27', 'Shawshank uses its confined setting to explore hope and human dignity with devastating effect; Maid in Manhattan uses a similar Cinderella framework to deliver something entirely frictionless and forgettable.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (297838, 263360, 2, 'erangolani27', 'Both are feel-good films built around an unlikely relationship, but Shawshank earns every emotional beat through accumulated suffering while Pretty Woman offers comfort without cost.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (297838, 46878, 1, 'erangolani27', 'Pairing one of the most emotionally rigorous films ever made with one of the laziest romantic comedy sequels is an instructive contrast in what storytelling ambition looks like.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (130128, 53921, 1, 'erangolani27', 'The Godfather is the defining film about power, loyalty, and corruption; Cannes Man is a self-indulgent industry comedy that lacks the discipline to make a single scene land.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (267038, 53921, 1, 'erangolani27', 'Tarantino''s masterwork shares a film-industry backdrop with Cannes Man but the comparison ends entirely there; one is a work of total creative control and the other is an unfocused vanity project.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (131780, 98681, 1, 'erangolani27', 'Goodfellas operates with the precision and authority of a master filmmaker; El Mariachi: 10 Years Later is a weak supplementary piece that adds nothing to its source material.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (191246, 264157, 1, 'erangolani27', 'The Lion King is one of the most emotionally and musically ambitious animated features ever made; Princess Diaries 2 is a pleasant but entirely disposable live-action sequel.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (337166, 244421, 1, 'erangolani27', 'Toy Story reinvented what animated storytelling could achieve; The Other Sister is a well-meaning but predictable drama that has nothing in common beyond a broadly sympathetic emotional register.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (59578, 74259, 2, 'erangolani27', 'Both feature Tim Burton''s aesthetic sensibility but Charlie and the Chocolate Factory channels it into something genuinely imaginative while Cry-Baby''s parody ambitions rarely land with the intended impact.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (96593, 1390, 1, 'erangolani27', 'Both are Spielberg films, but 1941 is his most chaotic and least focused effort; watching it after E.T. reveals how completely he had found his voice by 1982 by showing how lost it was just three years earlier.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (96593, 359297, 2, 'erangolani27', 'E.T. achieves its emotional impact through intimacy and a child''s perspective; War of the Worlds sacrifices the same child-centred framing for hollow spectacle that never generates equivalent feeling.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (14477, 359297, 2, 'erangolani27', 'Both are Spielberg films dealing with survival under impossible circumstances, but Amistad grounds its horror in historical truth while War of the Worlds mistakes kinetic chaos for genuine stakes.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (56304, 178994, 2, 'erangolani27', 'Casino is Scorsese operating at full cinematic power; Knockaround Guys borrows the mobster milieu but delivers a competent and entirely forgettable B-picture in comparison.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (267038, 69812, 2, 'erangolani27', 'Pulp Fiction uses its non-linear structure to create genuine meaning; Conspiracy Theory uses a superficially similar paranoid energy but drifts into generic thriller territory long before its conclusion.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (141544, 69812, 2, 'erangolani27', 'Heat''s procedural rigour and psychological depth make Conspiracy Theory''s romantic thriller contrivances feel particularly thin in comparison.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (280270, 280284, 3, 'erangolani27', 'Rocky''s power comes from its scraped-together authenticity; Rocky IV replaces that with Cold War mythology and a training montage that has more in common with a music video than the original film.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (280281, 280282, 3, 'erangolani27', 'Rocky II earns its sequel status by building on the original''s emotional foundation; Rocky III trades genuine drama for a commercial formula that the series never fully recovered from.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (306032, 41518, 3, 'erangolani27', 'Snatch''s overlapping crime plots crackle with invention and dark comedy; Blow covers similar criminal milieu but opts for a straightforward biopic structure that loses the genre energy entirely.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (62076, 258948, 1, 'erangolani27', 'Both are neo-noir films built around dangerous women and male vulnerability, but Chinatown uses that template to construct one of cinema''s great tragedies while Poison Ivy tips into melodrama that undercuts its own tension.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (233058, 44238, 1, 'erangolani27', 'Both attempt to combine occult horror with dark comedy but The Ninth Gate''s brooding atmosphere is everything Bordello of Blood''s cheap shocks are not.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (200521, 62460, 2, 'erangolani27', 'Both are ensemble films released within a year of each other, but Magnolia uses its mosaic structure to deliver something shattering and complex while Chocolat settles for feel-good charm that evaporates immediately after.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (247579, 258948, 2, 'erangolani27', 'Both are contained thrillers about a woman under threat in her own home, but Panic Room''s technical precision and Fincher''s control of tension make Poison Ivy''s melodramatic contrivances feel particularly obvious in comparison.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (208245, 109421, 2, 'erangolani27', 'Both are crowd-pleasing action-adjacent films built around charismatic leads, but Maverick''s wit and period charm make The Fast and the Furious'' stripped-down street racing feel thin and disposable.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (56871, 200864, 2, 'erangolani27', 'Both are light, charming films built around an attractive lead and a secret identity, but Catch Me If You Can''s true story and DiCaprio''s committed performance give it genuine stakes that Maid in Manhattan never attempts.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (30686, 46878, 1, 'erangolani27', 'The Basketball Diaries uses its star''s physical commitment to portray addiction with real anguish; pairing it with Bridget Jones 2''s weightless romantic comedy underscores how differently cinema can treat personal struggle.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (82967, 53921, 1, 'erangolani27', 'The Departed is a masterpiece of sustained deception and moral complexity; Cannes Man is a self-satisfied industry comedy that never earns a single laugh.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (304862, 44238, 1, 'erangolani27', 'Both attempt gothic horror with a comic edge but Sleepy Hollow''s production design and Depp''s performance give it genuine atmosphere that Bordello of Blood''s cheap sensibility cannot approach.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (94741, 109421, 2, 'erangolani27', 'Both use vehicular pursuit as their central dramatic engine but Duel uses the format to generate existential dread with almost no dialogue while The Fast and the Furious treats it as pure spectacle with nothing beneath the surface.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (39551, 1390, 1, 'erangolani27', 'Black Hawk Down depicts real military chaos with a solemnity that honours its subject; 1941 treats military chaos as slapstick farce and never generates a moment of comparable tension or weight.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (40199, 370017, 1, 'erangolani27', 'Blade Runner uses its action sequences to advance philosophical questions about identity and mortality; XXX uses its action sequences to demonstrate that action sequences exist.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (214755, 370017, 1, 'erangolani27', 'Minority Report embeds its action in a carefully constructed moral and political framework; XXX strips away every trace of such ambition to deliver an entirely empty exercise in stunt choreography.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (313059, 264157, 1, 'erangolani27', 'Stand by Me uses childhood friendship and a coming-of-age journey to achieve something genuinely moving; Princess Diaries 2 uses similar YA ingredients to deliver something frictionless and immediately forgettable.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (186439, 372525, 1, 'erangolani27', 'Lawrence of Arabia is among the most formally ambitious films ever made; Young Doctors in Love is a broad parody comedy that represents the opposite end of cinematic ambition in almost every conceivable way.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (191246, 372525, 1, 'erangolani27', 'Both are from the same broad era but the comparison ends entirely there; The Lion King is a landmark of emotional and musical cinema while Young Doctors in Love relies on cheap parody gags that land rarely.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (26844, 98681, 1, 'erangolani27', 'Back to the Future is a near-perfect piece of popular filmmaking; El Mariachi: 10 Years Later is a weak supplementary piece that cannot justify its own existence alongside the original film it revisits.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (106790, 200864, 1, 'erangolani27', 'Both are romantic films built around concealed identity and class difference, but In the Mood for Love uses that premise to achieve something almost unbearably elegant while Maid in Manhattan settles for comfortable predictability.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (348944, 244421, 1, 'erangolani27', 'The Usual Suspects is a meticulously constructed thriller whose every detail serves its central deception; The Other Sister is a well-meaning drama that telegraphs every beat from the opening scene.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (233058, 69812, 3, 'erangolani27', 'Both are paranoid thrillers built around a sceptic drawn into a conspiracy larger than himself, but The Ninth Gate''s European atmosphere and Polanski''s formal control give it a menace that Conspiracy Theory''s genre mechanics cannot replicate.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (49696, 85871, 1, 'erangolani27', 'Leone''s masterpiece uses the Western genre to explore moral nihilism with extraordinary craft; Diamonds Are Forever uses the spy genre for campy entertainment that mistakes knowing self-parody for genuine wit.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (164572, 14132, 1, 'erangolani27', 'Jackie Brown''s mature, character-driven crime story has nothing in common with American Pie 2 beyond a broadly ensemble cast; the contrast in dramatic ambition and execution is almost total.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (270971, 14132, 1, 'erangolani27', 'Raging Bull''s unflinching study of self-destruction is as far from American Pie 2''s cheerful vulgarity as cinema gets; the only meaningful connection is that both feature men behaving badly.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (174953, 264157, 1, 'erangolani27', 'Both feature young women navigating worlds that are trying to define them, but Nausicaa uses that premise for genuine ecological and political depth while Princess Diaries 2 settles for fairy-tale convention.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (141544, 46878, 1, 'erangolani27', 'Heat is one of cinema''s great portraits of professional obsession and lonely discipline; Bridget Jones 2 offers the opposite of all those qualities as comfort viewing, and the contrast could not be starker.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (254986, 372525, 1, 'erangolani27', 'The Pianist uses its wartime setting to deliver one of cinema''s most devastating portrayals of survival; pairing it with Young Doctors in Love''s hospital parody comedy is an exercise in extreme tonal contrast.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (159172, 159167, 2, 'erangolani27', 'Last Crusade is the perfect close to the original trilogy with genuine father-son warmth; the fourth film reopens that closed door and walks through it into a story that never justifies the reunion.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (159175, 159167, 2, 'erangolani27', 'Temple of Doom at its most extreme still generates kinetic adventure; Crystal Skull generates mostly disappointment, with digital spectacle standing in for the practical ingenuity that defined the earlier films.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (46169, 354178, 1, 'erangolani27', 'Braveheart uses its epic scale to deliver genuine emotion and sacrifice; A View to a Kill mistakes scale for impact and delivers a tired spy adventure that wastes every resource at its disposal.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (256632, 218808, 2, 'erangolani27', 'Both are adventure films that push their hero into fantastical set-pieces, but Pirates grounds its escapism in character and practical invention while Moonraker abandons both in favour of increasingly absurd spectacle.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (276085, 62460, 1, 'erangolani27', 'Both were released the same year but occupy completely different emotional registers; Requiem for a Dream is one of cinema''s most punishing experiences and Chocolat is one of its most comfortable, and the contrast is instructive.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (306032, 53921, 1, 'erangolani27', 'Both attempt to use the film industry or criminal world as a comedic backdrop, but Snatch''s tight plotting and sharp ensemble make Cannes Man''s shapeless self-indulgence feel particularly unearned.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (123435, 244421, 1, 'erangolani27', 'The Game engineers its protagonist''s psychological collapse with meticulous precision; The Other Sister is a sentimental drama where every development is telegraphed and every resolution comfortably predictable.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (210511, 14132, 1, 'erangolani27', 'Memento uses narrative structure itself as a dramatic instrument to explore how identity is constructed; American Pie 2 uses its sequel status mainly to recycle jokes from the original with diminishing returns.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (185628, 335336, 1, 'erangolani27', 'The Last Samurai earns its emotional payoff through a serious engagement with cultural collision and loss; Tomorrow Never Dies is a slick but hollow Bond entry where the stakes never feel real.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (39551, 370017, 1, 'erangolani27', 'Black Hawk Down uses real events and documentary-level detail to make the cost of combat feel viscerally real; XXX deploys similar action spectacle purely for entertainment with no interest in consequences.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (233058, 372525, 1, 'erangolani27', 'The Ninth Gate sustains a brooding occult atmosphere across its entire runtime; Young Doctors in Love is a parody comedy that mistakes irreverence for wit and rarely achieves either.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (97360, 53921, 2, 'erangolani27', 'Both are films about filmmaking outsiders, but Ed Wood transforms its subject''s incompetence into something genuinely moving through Depp''s committed performance and Burton''s affectionate direction; Cannes Man achieves nothing comparable.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (304862, 372525, 1, 'erangolani27', 'Both attempt genre parody but Sleepy Hollow is a fully realised gothic horror with real atmosphere while Young Doctors in Love is a broad comedy that exhausts its premise in the first act.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (116556, 53921, 2, 'erangolani27', 'Both are low-budget films made outside the mainstream, but Following uses its constraints to produce something formally inventive while Cannes Man uses its festival setting to deliver an unfocused vanity project.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (67388, 69812, 2, 'erangolani27', 'Both are films about obsession and identity built around a compulsive pursuit, but Color of Money uses pool as a genuine dramatic vehicle while Conspiracy Theory''s paranoid plotting never generates equivalent tension.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (253010, 200864, 1, 'erangolani27', 'Both use a cross-class relationship as their emotional engine, but Perfect World earns every moment of feeling through real dramatic risk while Maid in Manhattan never departs from its genre comfort zone.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (30976, 30952, 1, 'erangolani27', 'Mask of the Phantasm demonstrates how seriously the Batman mythology can be treated even in animation; Batman and Robin demonstrates the opposite with equal thoroughness.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (30965, 30952, 3, 'erangolani27', 'Batman Forever is a flawed but watchable compromise between Burton''s darkness and a more commercial sensibility; Batman and Robin abandons even that compromise and delivers a film that is almost entirely indefensible.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (291495, 372525, 2, 'erangolani27', 'Both are comedies built around broad satirical targets, but Scrooged uses Murray''s deadpan delivery and the Dickens framework to earn its sentimental finale while Young Doctors in Love never develops enough comic identity to justify its parody premise.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (312150, 370017, 2, 'erangolani27', 'Both are action films aimed at demonstrating that spectacle can substitute for character, but Spy Kids at least has a genuine warmth and family dynamic beneath its set-pieces while XXX has nothing beneath its set-pieces at all.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (276085, 30686, 9, 'erangolani27', 'Both are unflinching portraits of addiction that use a young man''s disintegration as their emotional core; DiCaprio''s physical rawness in Basketball Diaries finds its formal counterpart in Aronofsky''s assault on the senses.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (290070, 254986, 10, 'erangolani27', 'Schindler''s List and The Pianist are the two most essential Holocaust films ever made; experienced together they offer complementary perspectives on survival, witness, and the specific horror of that history.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (46169, 340652, 8, 'erangolani27', 'Both are sword-and-sandal epics built around legendary battles and personal sacrifice; if Braveheart''s emotional sweep appeals to you, Troy''s similar scale and ambition will land in the same place.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (67395, 290070, 9, 'erangolani27', 'Both are Spielberg films that demand something from the audience and deliver something lasting in return; each uses a particular historical horror to explore survival, identity, and the stubborn persistence of dignity.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (56304, 209158, 8, 'erangolani27', 'Tracing Scorsese from his earliest street-level crime films to his most operatic is one of cinema''s great director retrospectives; the thematic obsessions remain identical across three decades.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (238072, 348944, 9, 'erangolani27', 'Both are ensemble crime films built around an elaborate con that the audience only fully understands at the very end; Ocean''s Eleven plays it for charm while The Usual Suspects plays it for menace.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (159665, 118367, 1, 'erangolani27', 'Inglourious Basterds is Tarantino''s most controlled and formally ambitious film; Four Rooms represents the opposite of controlled, an anthology that mistakes chaos for energy and never achieves the discipline that makes Tarantino''s best work so effective.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (276217, 53921, 1, 'erangolani27', 'Reservoir Dogs announced a major filmmaking voice with extraordinary efficiency and no wasted energy; Cannes Man uses the film world as a backdrop without finding anything interesting to say about it.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (97360, 372525, 1, 'erangolani27', 'Ed Wood finds genuine pathos in its subject''s incompetence and turns it into a love letter to the creative impulse; Young Doctors in Love treats incompetence as straightforward comedy fodder and never elevates it.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (185704, 372525, 1, 'erangolani27', 'Last Temptation of Christ is one of the most theologically serious and genuinely provocative films ever made; pairing it with a hospital parody comedy underscores how wide cinema''s spectrum of ambition truly is.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (160524, 86263, 1, 'erangolani27', 'Both were released in 2002 and both feature a protagonist operating under extreme psychological pressure, but Insomnia uses that premise to build a genuine moral thriller while Die Another Day delivers only hollow spectacle.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (177369, 53921, 1, 'erangolani27', 'King of Comedy uses celebrity obsession and the entertainment industry as material for something genuinely unsettling; Cannes Man mines the same industry backdrop for cheap laughs and produces almost none.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (181766, 1390, 1, 'erangolani27', 'Kundun is one of Scorsese''s most patient and formally beautiful films; 1941 is one of Spielberg''s least controlled, and the contrast between the two directors'' weakest and most meditative efforts is instructive.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (160375, 280305, 2, 'erangolani27', 'Both deal with physical limitation and the struggle to define identity outside of athletic achievement, but Inside Moves handles that theme with quiet dignity while Rocky V reduces it to franchise mechanics.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (253010, 46878, 1, 'erangolani27', 'Perfect World earns its emotional resonance through real dramatic risk and a relationship built on genuine complexity; Bridget Jones 2 settles for the comfortable predictability of a sequel that adds nothing to what came before.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (114955, 280305, 2, 'erangolani27', 'Both are coming-of-age stories about young men learning the limits of hero worship, but Flamingo Kid handles that lesson with wit and specificity while Rocky V turns the same theme into a tired franchise entry.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (116556, 370017, 1, 'erangolani27', 'Following uses its extreme budget constraints to produce something formally inventive and genuinely tense; XXX uses its enormous budget to produce something formally inert and entirely disposable.', null);

INSERT IGNORE INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (311037,311038,10,'Yaron','Manual - direct sequel','Direct sequel and the peak of the Raimi trilogy; essential for anyone who liked the first.');

INSERT IGNORE INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (313459,313478,10,'Yaron','Manual - direct sequel','Empire continues the story directly and deepens every character while raising the stakes.');

INSERT IGNORE INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (313478,313479,9,'Yaron','Manual - direct sequel','Return of the Jedi resolves the cliffhanger ending of Empire; you need both.');

INSERT IGNORE INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (194497,194502,10,'Yaron','Manual - direct sequel','One continuous story split in two; finishing Fellowship leads straight into Two Towers.');

