INSERT IGNORE INTO movies_recommendations (base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment)
WITH Top_Movies AS (
  SELECT 207992 AS movie_id, 10 AS rating, 'Sci-Fi' AS genre_group UNION ALL
  SELECT 313478, 10, 'Sci-Fi' UNION ALL
  SELECT 313479, 9, 'Sci-Fi' UNION ALL
  SELECT 289109, 9, 'Drama/War' UNION ALL
  SELECT 290070, 10, 'Drama/War' UNION ALL
  SELECT 267038, 10, 'Crime' UNION ALL
  SELECT 131780, 9, 'Crime' UNION ALL
  SELECT 297838, 10, 'Drama' UNION ALL
  SELECT 159172, 9, 'Adventure' UNION ALL
  SELECT 130128, 10, 'Crime' UNION ALL
  SELECT 130129, 10, 'Crime' UNION ALL
  SELECT 337166, 9, 'Animation' UNION ALL
  SELECT 215876, 8, 'Action' UNION ALL
  SELECT 238072, 8, 'Crime'
)
SELECT
  t1.movie_id AS base_movie_id,
  t2.movie_id AS recommended_movie_id,
  LEAST(t1.rating, t2.rating) AS recommendation,
  'GiliBarak' AS suggested_by,
  CASE

    WHEN t1.movie_id IN (130128, 130129) AND t2.movie_id IN (130128, 130129)
      THEN 'Both are epic chapters of the Corleone family saga, showcasing some of the greatest acting and direction in film history.'


    WHEN t1.movie_id IN (313478, 313479) AND t2.movie_id IN (313478, 313479)
      THEN 'Both are legendary space opera chapters with iconic characters, epic conflicts, and a John Williams score.'


    WHEN t1.genre_group = 'Sci-Fi' AND t2.genre_group = 'Sci-Fi'
      THEN 'Both are groundbreaking science fiction masterpieces with visionary world-building and philosophical depth.'


    WHEN t1.genre_group = 'Crime' AND t2.genre_group = 'Crime'
      THEN 'Both are gripping crime classics that offer a realistic, gritty look at the criminal underworld.'


    WHEN t1.genre_group = 'Drama/War' AND t2.genre_group = 'Drama/War'
      THEN 'Both are powerful and emotionally intense historical dramas focused on human conflict and sacrifice.'


    WHEN (t1.genre_group = 'Crime' AND t2.genre_group IN ('Action', 'Adventure')) OR (t1.genre_group IN ('Action', 'Adventure') AND t2.genre_group = 'Crime')
      THEN 'Both are stylish, fast-paced thrillers featuring high stakes, clever plans, and charismatic leads.'


    WHEN (t1.genre_group = 'Drama' AND t2.genre_group = 'Drama/War') OR (t1.genre_group = 'Drama/War' AND t2.genre_group = 'Drama')
      THEN 'Both are deeply moving character studies exploring moral choices and resilience under pressure.'


    ELSE 'Both are landmark cinematic masterpieces with stellar performances, tight screenplays, and massive cultural impact.'
  END AS justification,
  NULL AS comment
FROM Top_Movies t1
CROSS JOIN Top_Movies t2
WHERE t1.movie_id != t2.movie_id;

INSERT IGNORE INTO movies_recommendations (base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment)
WITH Good_Movies AS (
  SELECT 30959 AS movie_id UNION ALL
  SELECT 30955 UNION ALL
  SELECT 311038 UNION ALL
  SELECT 319602 UNION ALL
  SELECT 207992 UNION ALL
  SELECT 130128 UNION ALL
  SELECT 130129 UNION ALL
  SELECT 238072 UNION ALL
  SELECT 267038 UNION ALL
  SELECT 276217 UNION ALL
  SELECT 131780 UNION ALL
  SELECT 56304 UNION ALL
  SELECT 82967 UNION ALL
  SELECT 291698 UNION ALL
  SELECT 301540 UNION ALL
  SELECT 141544 UNION ALL
  SELECT 297838 UNION ALL
  SELECT 159172 UNION ALL
  SELECT 289109 UNION ALL
  SELECT 290070
),
Bad_Movies AS (
  SELECT 30952 AS movie_id, 2 AS rec, 'superhero movies' AS common_link, 'Batman & Robin is campy, silly, and widely considered one of the worst superhero films ever made' AS reason UNION ALL
  SELECT 311040, 5, 'superhero movies', 'Spider-Man 3 is overstuffed with villains and lacks the focused storytelling of the classics' UNION ALL
  SELECT 238073, 5, 'crime or heist films', 'Ocean''s Twelve has a convoluted plot and lacks the sharp execution of the best heist movies' UNION ALL
  SELECT 280305, 5, 'inspiring sports dramas', 'Rocky V is a disappointing sequel with a weak, messy plot' UNION ALL
  SELECT 220805, 5, 'action-focused films', 'Mr. and Mrs. Smith relies too much on simple shooting and action rather than a strong narrative' UNION ALL
  SELECT 188511, 5, 'action buddy-cop films', 'Lethal Weapon 4 has an overstuffed, messy story that lacks the tight pacing of the original' UNION ALL
  SELECT 1390, 5, 'films directed by Steven Spielberg', '1941 is a loud, chaotic comedy that fails to capture the dramatic excellence of his best work' UNION ALL
  SELECT 149287, 5, 'films directed by Steven Spielberg', 'Hook is a sentimental family movie that lacks the mature depth of his historical dramas' UNION ALL
  SELECT 12744, 5, 'films directed by Steven Spielberg', 'Always is a slow, overly sentimental drama that does not match the epic scale of his best films'
)
SELECT
  g.movie_id AS base_movie_id,
  b.movie_id AS recommended_movie_id,
  b.rec AS recommendation,
  'GiliBarak' AS suggested_by,
  CONCAT('Though both movies are ', b.common_link, ', it is a bad recommendation since ', b.reason) AS justification,
  NULL AS comment
FROM Good_Movies g
CROSS JOIN Bad_Movies b;

