INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (313477, 313478, 8, 'Tomer-Spector', 'Revenge of the Sith makes the Vader reveal in Empire dramatically richer. Knowing the fall makes the mask mean more.', null);

