INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (97727, 304862, 8, 'orimor25', 'Both Burton-Depp collaborations where Depp plays a misunderstood outsider. Edward Scissorhands in suburbia, Ichabod Crane in rural New York.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (97360, 97727, 8, 'orimor25', 'Both Burton-Depp films about eccentric characters who do not fit in. Ed Wood is a comedy, Scissorhands is a fairy tale, both are about belonging.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (70959, 59578, 7, 'orimor25', 'Both Burton films with elaborate fantasy production design. Corpse Bride is stop-motion, Charlie is live action, but the visual imagination is the same.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (337166, 190869, 8, 'orimor25', 'Both animated films that deal with surprisingly mature emotions underneath colourful surfaces. Toy Story tackles jealousy, Lilo and Stitch tackles family loss.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (218219, 174953, 10, 'orimor25', 'Both Miyazaki films about the conflict between nature and civilisation. Mononoke and Nausicaa share a moral complexity rare in animation.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (300229, 337166, 7, 'orimor25', 'Both animated films that redefined what the genre could do for their respective studios. Shrek for DreamWorks, Toy Story for Pixar.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (330670, 54209, 8, 'orimor25', 'Both feature De Niro as a terrifyingly abusive authority figure. This Boy''s Life as a stepfather, Cape Fear as a stalker, equally uncomfortable to watch.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (56871, 25192, 8, 'orimor25', 'Both DiCaprio-led biographical films directed by major filmmakers. Catch Me If You Can with Spielberg, Aviator with Scorsese. Both portray obsessive real figures.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (30686, 330670, 8, 'orimor25', 'Both films starring a young DiCaprio in intense dramatic roles before he became a leading man. Basketball Diaries and This Boy''s Life show his raw early talent.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (256632, 113506, 6, 'orimor25', 'Both Johnny Depp performances but in completely different modes. Captain Jack is flamboyant comedy, J.M. Barrie is restrained drama. Depp''s range on display.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (41518, 30686, 7, 'orimor25', 'Both films about young men pulled into drug culture and paying the price. Blow and Basketball Diaries share a rise-and-fall structure and refuse to romanticise the lifestyle.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (188507, 188509, 9, 'orimor25', 'Lethal Weapon and Lethal Weapon 2 are the two best entries in the franchise. The addition of Pesci in the sequel adds a comic energy the first film did not need but the second benefits from.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (215876, 215880, 8, 'orimor25', 'Mission Impossible and MI3 are the two best entries in the franchise. De Palma started strong and Abrams brought the series back to that level after the Woo detour.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (311038, 142491, 7, 'orimor25', 'Both are superhero films from the mid-2000s that prioritize character over spectacle. Spider-Man 2 and Hellboy both have villains with real emotional depth.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (319602, 319613, 9, 'orimor25', 'Superman and Superman II are the definitive superhero film pairing. The first builds the myth, the second tests it with real villainy.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (142491, 142492, 9, 'orimor25', 'Hellboy and Hellboy 2 are Del Toro expanding his own creation. The sequel goes further into fantasy and the Golden Army is a stronger visual achievement.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (312150, 210739, 7, 'orimor25', 'Both are family-friendly spy comedies with inventive gadgets and creature designs. Spy Kids is MIB for younger audiences, same playful energy.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (240327, 259826, 8, 'orimor25', 'Both are 1970s/80s supernatural horror films that build dread through a family under threat. The Omen uses biblical fear, Poltergeist uses suburban fear.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (291495, 208245, 7, 'orimor25', 'Both are comedies that rely entirely on the charisma of a single lead. Bill Murray carries Scrooged, Mel Gibson carries Maverick, both are effortless fun.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (644, 66194, 8, 'orimor25', 'Both are 1990s high school comedies based on classic literature. 10 Things from Shakespeare, Clueless from Austen, both smarter than they need to be.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (263360, 151616, 7, 'orimor25', 'Both are light romantic comedies with attractive leads and zero pretensions. Pretty Woman and How to Lose a Guy are comfort viewing in the same category.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (333856, 263360, 7, 'orimor25', 'Both are crowd-pleasing romance blockbusters from the 1990s. Titanic and Pretty Woman are the decade''s two most iconic love stories despite very different stakes.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (46169, 185628, 7, 'orimor25', 'Both are epic historical films about warriors fighting with honour against overwhelming odds. Braveheart in Scotland, Last Samurai in Japan.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (297838, 280270, 8, 'orimor25', 'Both are films about underdogs who refuse to give up when everything is stacked against them. Shawshank and Rocky are the two greatest underdog stories in cinema.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (67388, 270971, 7, 'orimor25', 'Both Scorsese films about competitive masculinity. Color of Money through pool, Raging Bull through boxing. Same director exploring the same obsessive drive.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (253010, 318388, 7, 'orimor25', 'Both are road/chase films set in Texas with morally complex protagonists. A Perfect World and Sugarland Express share Spielberg/Eastwood''s interest in fugitives with humanity.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (350189, 218219, 7, 'orimor25', 'Both are Japanese animated films with gothic/mythological settings and morally complex characters. Vampire Hunter D and Mononoke are the darker side of anime storytelling.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (33492, 62460, 7, 'orimor25', 'Both are European films centred on food and romance. Bella Martha is a German chef falling in love, Chocolat is a French chocolatier doing the same.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (220276, 333856, 7, 'orimor25', 'Both are visually spectacular love stories that prioritise emotion over realism. Moulin Rouge and Titanic are the two most maximalist romances of their era.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (158999, 359297, 6, 'orimor25', 'Both are alien invasion blockbusters but Independence Day plays it for spectacle while War of the Worlds goes for genuine fear. Same genre, different goals.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (313160, 13547, 8, 'orimor25', 'Both are documentary looks at legendary directors in their earliest stages. Kubrick: A Life in Pictures and Amblin'' show genius before the world noticed.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (185704, 181766, 7, 'orimor25', 'Both are Scorsese films about spiritual belief and its costs. Last Temptation explores Christianity, Kundun explores Buddhism. Same reverence, different traditions.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (230947, 7842, 8, 'orimor25', 'Both are Scorsese projects set in New York. New York Stories is an anthology, After Hours is a single night, both capture the city''s chaotic energy.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (109421, 370017, 7, 'orimor25', 'Both are early 2000s action films built around fast vehicles and big stunts with no pretensions about what they are. Same target audience, same energy.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (30959, 30952, 2, 'orimor25', 'Both are Batman films but the comparison ends there. Begins is grounded realism, Batman and Robin is neon camp. Same character, opposite quality.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (30955, 30952, 2, 'orimor25', 'Burton''s Batman was dark and operatic. Batman and Robin is garish and embarrassing. The franchise fell off a cliff between these two.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (10830, 10945, 3, 'orimor25', 'Both are Alien franchise films but Alien 3 destroyed everything the first two built. Same universe, completely different quality and care.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (10920, 10945, 3, 'orimor25', 'Aliens is one of the best sequels ever made. Alien 3 killed off the surviving characters in the opening credits. Same franchise, devastating quality drop.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (311037, 311040, 4, 'orimor25', 'Spider-Man launched a franchise. Spider-Man 3 buried it under too many villains and not enough focus. Same director with diminishing returns.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (311038, 311040, 3, 'orimor25', 'Spider-Man 2 elevated the genre. Spider-Man 3 crammed in Venom, Sandman, and Harry at once and gave none of them the space they needed.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (280270, 280305, 3, 'orimor25', 'Rocky is a masterpiece about dignity. Rocky V took the same character back to the streets and wasted the opportunity with a weak new rival.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (280270, 280306, 2, 'orimor25', 'Rocky is one of the greatest sports films ever made. Rocky VI is a mislabelled entry that should not exist in the same franchise.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (313478, 313474, 3, 'orimor25', 'Empire is the peak of Star Wars. Phantom Menace is the most disappointing entry. Same universe but the prequel never captures the magic of the original.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (313478, 313476, 3, 'orimor25', 'Empire is mythological storytelling at its best. Attack of the Clones is a romance on Naboo that never earns the emotional weight it aims for.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (271095, 159167, 3, 'orimor25', 'Raiders defined adventure cinema. Indiana Jones 4 put him in a fridge and introduced aliens. Same character, completely different quality.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (159172, 159167, 3, 'orimor25', 'Last Crusade closed the trilogy perfectly. Indiana Jones 4 reopened it with a premise that does not fit the world the original trilogy built.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (130945, 86263, 2, 'orimor25', 'GoldenEye reinvented Bond with intelligence. Die Another Day undid all of it with an invisible car and an ice palace. Same actor, opposite trajectories.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (120574, 218808, 2, 'orimor25', 'From Russia with Love is grounded espionage. Moonraker sends Bond to space. Same franchise, completely different relationship with reality.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (130953, 85871, 4, 'orimor25', 'Goldfinger is peak Connery Bond. Diamonds Are Forever is visibly tired Connery going through the motions. Same actor, same character, different levels of engagement.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (188507, 188510, 4, 'orimor25', 'Lethal Weapon established the buddy cop genre. Lethal Weapon 3 settled into formula and replaced edge with toilet humour. The chemistry survives but the writing does not.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (188507, 188511, 3, 'orimor25', 'Lethal Weapon is a sharp action film. Lethal Weapon 4 is an overstuffed franchise entry that wastes Jet Li and has run completely out of ideas.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (238072, 238073, 4, 'orimor25', 'Ocean''s Eleven is an elegant heist film. Ocean''s Twelve is convoluted for the sake of it. Same cast, much less clarity in the story.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (256632, 256631, 4, 'orimor25', 'Curse of the Black Pearl is a perfectly self-contained adventure. Pirates 2 extends the story but spins its wheels badly in the middle third.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (215876, 215879, 3, 'orimor25', 'Mission Impossible is a smart thriller. MI2 is a John Woo action film with no brain underneath the stunts. Same franchise, completely different ambitions.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (312150, 312152, 3, 'orimor25', 'Spy Kids is inventive family filmmaking. Spy Kids 3D abandoned story for a gimmick that overwhelmed everything else. The franchise ran out of ideas fast.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (312150, 312151, 4, 'orimor25', 'Spy Kids 1 had tight charm. Spy Kids 2 went bigger but lost the focus that made the original work. The island creatures are imaginative but the plot is not.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (300229, 300230, 5, 'orimor25', 'Shrek is iconic and original. Shrek 2 is entertaining but slightly less original. If you loved the first you will enjoy the second but not as much.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (139655, 139650, 4, 'orimor25', 'Prisoner of Azkaban is the creative peak of the HP series. Chamber of Secrets is the most formulaic entry. Both set in Hogwarts but the directorial vision is worlds apart.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (280281, 280284, 5, 'orimor25', 'Rocky II is grounded drama. Rocky IV is Cold War propaganda with a training montage. Same character, completely different tone and ambition.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (280284, 280282, 5, 'orimor25', 'Rocky IV and Rocky III are both the more commercial, less serious entries. Both work as entertainment but neither reaches the emotional depth of the first two.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (326155, 47130, 4, 'orimor25', 'Both are films about New York night workers losing their grip on sanity. Taxi Driver is De Niro at his peak, Bringing Out the Dead is Cage in a more uneven film.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (131780, 230963, 4, 'orimor25', 'Both Scorsese-De Niro collaborations but Goodfellas is a masterpiece and New York, New York is an uneven musical experiment. Same partnership, different results.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (129185, 340652, 3, 'orimor25', 'Both are ancient world epics with large-scale battles. Gladiator finds its emotional core, Troy loses its characters in spectacle. Same genre, different depth.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (56871, 200864, 3, 'orimor25', 'Both are light entertainment with charming leads but Catch Me If You Can has Spielberg''s craft behind it. Maid in Manhattan is a thin template in comparison.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (112290, 292671, 3, 'orimor25', 'Both feature protagonists dealing with alternate versions of themselves. Fight Club executes the concept brilliantly, Secret Window compresses it too aggressively.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (97727, 59578, 5, 'orimor25', 'Both Burton-Depp films about eccentric outsiders. Scissorhands found the perfect emotional balance, Chocolate Factory has the style but not quite the heart.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (267038, 118367, 4, 'orimor25', 'Both are Tarantino-connected anthology films. Pulp Fiction perfected the format, Four Rooms is uneven with only the Tarantino and Rodriguez segments working.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (263360, 283410, 3, 'orimor25', 'Roberts and Gere reunited but Runaway Bride never recaptures Pretty Woman''s chemistry. Same stars, same genre, much less magic the second time.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (14132, 14157, 3, 'orimor25', 'Both American Pie sequels reuniting the original cast. Pie 2 was formulaic, American Reunion was nostalgia without substance. Diminishing returns with each entry.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (46878, 283410, 4, 'orimor25', 'Both are romantic comedy sequels that fail to recapture the original''s charm. Bridget Jones 2 and Runaway Bride both settle into predictable formula.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (290070, 100130, 4, 'orimor25', 'Both are Spielberg WWII films but Schindler''s List is a masterpiece and Empire of the Sun is a more patient, less emotionally direct film. Same era, different impact.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (267038, 350424, 3, 'orimor25', 'Both are 1990s/2000s films that play with reality and identity. Pulp Fiction does it through structure, Vanilla Sky does it through dream logic. One succeeds far more than the other.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (165961, 1390, 2, 'orimor25', 'Both are early Spielberg blockbusters but Jaws is a masterclass in suspense and 1941 is an exhausting comedy that sacrifices story for noise.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (96593, 21213, 4, 'orimor25', 'Both are Spielberg sci-fi films about a being trying to find its way home. E.T. achieves it with economy, AI meanders through a bloated second act to get there.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (210511, 292671, 3, 'orimor25', 'Both are psychological thrillers with unreliable protagonists. Memento executes the concept brilliantly while Secret Window rushes through it without enough depth.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (291698, 233058, 4, 'orimor25', 'Both are dark thrillers about obsession and hidden evil. Se7en is relentlessly intense, Ninth Gate is atmospheric but lacks the same urgency.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (306032, 178994, 3, 'orimor25', 'Both are ensemble crime films with overlapping storylines. Snatch does it with wit and precision, Knockaround Guys has the cast but not the script.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (30959, 30965, 3, 'orimor25', 'Both are Batman films but Begins redefined the character while Forever never found its tone between dark and campy. Same Gotham, different levels of commitment.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (289109, 340652, 3, 'orimor25', 'Both are epic war films with massive battle sequences. Saving Private Ryan finds humanity in chaos, Troy gets lost in spectacle without enough characters to anchor it.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (129185, 1121, 3, 'orimor25', 'Both are Ridley Scott historical epics. Gladiator found its emotional core, 1492 is ambitious but slow and never connects on the same human level.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (151616, 200864, 4, 'orimor25', 'Both are early 2000s romantic comedies with charming leads. How to Lose a Guy has a clever premise, Maid in Manhattan has a thinner one in the same template.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (644, 1038, 4, 'orimor25', 'Both are fun, light films aimed at a similar audience. 10 Things has genuine wit from its Shakespeare source, 13 Going on 30 is harmless but less sharp.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (66194, 264157, 3, 'orimor25', 'Both are coming-of-age comedies but Clueless is a sharp satire of high school culture. Princess Diaries 2 falls back on the same fish-out-of-water formula without adding anything.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (350424, 69812, 4, 'orimor25', 'Both are conspiracy-tinged thrillers starring major leads. Vanilla Sky has ambition but uneven execution, Conspiracy Theory has Gibson and Roberts in a premise that deflates at the end.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (256839, 370017, 4, 'orimor25', 'Both are Vin Diesel action vehicles. Pitch Black uses him in a smart sci-fi setting, XXX uses him in a disposable action template. Same star, different ambition.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (56304, 8183, 4, 'orimor25', 'Both Scorsese period films but Casino is propulsive and electric while Age of Innocence is restrained and meditative. Fans of one may find the other too different in pace.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (297838, 270628, 2, 'orimor25', 'Both are films about hope under terrible circumstances. Shawshank earns its emotion honestly, Radio Flyer handles a painful premise with too much sentimentality.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (192702, 189403, 5, 'orimor25', 'Both are Timothy Dalton Bond entries. Living Daylights reinvented the character, Licence to Kill pushed him into generic 1980s action territory. Same actor, different success.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (335336, 368418, 5, 'orimor25', 'Both are middle-era Brosnan Bond films. Tomorrow Never Dies is slick but hollow, World Is Not Enough wastes Marceau. Both are watchable and forgettable.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (192514, 354178, 4, 'orimor25', 'Both are Roger Moore Bond films. Live and Let Die has Caribbean charm, View to a Kill wastes Walken on thin material. Same era, declining quality.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (332065, 372233, 5, 'orimor25', 'Both are mid-1960s Connery Bond spectacles. Thunderball drags underwater, You Only Live Twice prioritises sets over story. Neither reaches the level of Goldfinger.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (117314, 203649, 5, 'orimor25', 'Both are Roger Moore Bond entries with scenic locations and competent but unmemorable villains. Neither rises above the middle tier of the franchise.', null);

INSERT IGNORE INTO movies_recommendations(base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment) values (218808, 86263, 5, 'orimor25', 'Both are Bond films that abandoned reality entirely. Moonraker went to space, Die Another Day went invisible. Neither works as a thriller because neither is grounded.', null);

