INSERT IGNORE INTO movies_recommendations
VALUES (
  227925,
  207099,
  9,
  'roni88882-ctrl',
  'MASH was Altman''s breakthrough and Nashville his masterpiece, both use overlapping dialogue, ensemble casts, and dark comedy to describe how institutions grind individuals down while the individuals keep performing normalcy.',
  NULL
);

INSERT IGNORE INTO movies_recommendations
VALUES (
  194818,
  41988,
  9,
  'roni88882-ctrl',
  'Blue Velvet is the clearest entry point for Lost Highway, both films peel back a surface of domestic normality to reveal a violently surreal underworld, and both use sexuality and crime as the doorway between those two realities.',
