INSERT IGNORE INTO movies_recommendations (base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment)
VALUES (969, 349, 10, 'Yoavkeidar9', 'Both are masterclass courtroom dramas anchored by explosive lead performances that expose the structural corruption and moral hypocrisy embedded within legal institutions.', '');

INSERT IGNORE INTO movies_recommendations (base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment)
VALUES (52, 53, 10, 'Yoavkeidar9', 'The direct sequel maintains the same extraordinary standard of practical stunt choreography — the bicycle chases, clock tower sequences, and physical commitment of the performers are matched across both films with remarkable consistency.', '');

INSERT IGNORE INTO movies_recommendations (base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment)
VALUES (69, 548, 10, 'Yoavkeidar9', 'Both films dissect military institutional culture with sustained analytical precision, using legal or procedural frameworks to expose how bureaucratic systems dehumanize the individual while insulating authority from accountability.', '');

INSERT IGNORE INTO movies_recommendations (base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment)
VALUES (955, 1016, 10, 'Yoavkeidar9', 'Both construct their mysteries through layered temporal revelation, deploying structural information management with such precision that the assembled narrative satisfies as a coherent formal achievement rather than mere genre exercise.', '');

INSERT IGNORE INTO movies_recommendations (base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment)
VALUES (995, 1051, 10, 'Yoavkeidar9', 'Both European comedies exploit the identical dramatic premise of desperate characters hunting for hidden treasure inside antique chairs, and both execute the comedic escalation with a structural elegance that transcends the apparent simplicity of the conceit.', '');

INSERT IGNORE INTO movies_recommendations (base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment)
VALUES (73, 606, 10, 'Yoavkeidar9', 'Both comedies derive their primary dramatic energy from protagonists whose psychological deterioration is rendered with precise comic calibration, using the midlife crisis and suburban paranoia as vehicles for genuine character observation.', '');

INSERT IGNORE INTO movies_recommendations (base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment)
VALUES (223, 603, 10, 'Yoavkeidar9', 'Both films function as artistic extensions of their musical subjects rather than mere documentation, constructing a visual and editorial language that reflects the aesthetic values of the music being portrayed with genuine curatorial intelligence.', '');

INSERT IGNORE INTO movies_recommendations (base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment)
VALUES (249, 165, 10, 'Yoavkeidar9', 'Both retrospective documentaries engage their canonical subjects at a level of analytical depth proportionate to the films'' historical significance, providing scholarly-grade contextual material that meaningfully extends understanding of the primary works.', '');

INSERT IGNORE INTO movies_recommendations (base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment)
VALUES (1019, 1018, 10, 'Yoavkeidar9', 'The feature film engages the temporal loop premise with demonstrably greater formal rigor than most contemporaneous treatments, and viewers who appreciated the short film''s structural precision will find the same logical discipline expanded across a fuller narrative canvas.', '');

INSERT IGNORE INTO movies_recommendations (base_movie_id, recommended_movie_id, recommendation, suggested_by, justification, comment)
